import React from 'react';
import FullWidthPageLayout from '@layouts/FullWidthPage';
import DummyAppScreenHeroBanner from '@components/DummyAppScreenHeroBanner';
import Seo from '@components/Seo';

export default function AboutPage() {
	return (
		<FullWidthPageLayout>
			<DummyAppScreenHeroBanner />
			{/* <article>
				<h1>About</h1>
				<img src="https://source.unsplash.com/random/400x300" alt="a simple description" />
			</article> */}
		</FullWidthPageLayout>
	);
}

export function Head({ location }) {
	return <Seo title="About Kaagzi" urlPath={'/' + location.pathname} />;
}
